import { PublicActionPage } from '@domain/publicActionPage';
import { AddressFieldProps } from '@pages/ActionPages/pages/ActionPagesBuilder/components/ActionPage/ActionPageForm/Fields/Address/Address';
import { useCarouselItemAndDirection } from '@pages/ActionPages/pages/PublicActionPage/ActionPageView/ActionPageLayout/ActionPageBody/ActionPageFormPresentation/hooks/useFormCarousel';
import { useTotalAmount } from '@pages/ActionPages/pages/PublicActionPage/ActionPageView/ActionPageLayout/ActionPageBody/hooks';
import { useFeatureFlag } from '@state/featureFlags';
import clsx from 'clsx';
import { ReactNode, useCallback } from 'react';
import { useFormContext } from 'react-hook-form';
import { useTranslation } from 'react-i18next';
import { useTicketTotalAmount } from 'src/builder/PublicActionPage/ActionPageView/ActionPageLayout/ActionPageBody/hooks';
import { Button } from '../../Button';
import {
  AmericanExpressColorIcon,
  DiscoverColorIcon,
  MasterCardColorIcon,
  VisaColorIcon,
} from '../../icons';
import { Label } from '../../Label';
import { Meta } from '../../Meta';
import { ExpressApplePayButton } from './ExpressApplePayButton';
import { ExpressGooglePayButton } from './ExpressGooglePayButton';
import { ExpressOpenNodeButton } from './ExpressOpenNodeButton/ExpressOpenNodeButton';
import { SignInLink } from './SignInLink/SignInLink';

type Props = Pick<AddressFieldProps, 'fieldPrefix' | 'fieldPrefixDelimiter'> & {
  actionPage: PublicActionPage;
  alignCheckoutLabel?: string;
  // show the 'Already have an account?' label
  checkoutLabel?: ReactNode;
  isCustomDomain?: boolean;
  isEmbedded: boolean;
  isLoading?: boolean;
  isPreview?: boolean;
  showPayWithCardOrBankButton?: boolean;
  // show the button for Anedot
  showSignInPrompt: boolean;
};

export const ExpressCheckoutButtons = ({
  actionPage,
  alignCheckoutLabel,
  checkoutLabel,
  fieldPrefix,
  fieldPrefixDelimiter,
  isCustomDomain,
  isEmbedded,
  isLoading,
  isPreview = false,
  showPayWithCardOrBankButton,
  showSignInPrompt,
}: Props) => {
  const { t } = useTranslation('common');
  const donationAmount = useTotalAmount();
  const ticketAmount = useTicketTotalAmount(actionPage);
  const { setValue, watch } = useFormContext();
  const promoCodeDiscount = watch('promoCodeDiscount');
  const region = watch('addressAttributes.region');
  const totalAmount = Math.max(donationAmount + ticketAmount - promoCodeDiscount, 0);
  const eventTicketsAttributes = watch('eventTicketsAttributes');
  const expressCheckoutMethod = isPreview ? null : watch('expressCheckoutMethod');
  const enableOpenNode = useFeatureFlag('actionPages.enableOpenNode', false, actionPage.account.id);

  const { disallowedStates } = actionPage.account.accountConfiguration;
  const isDisallowedState = disallowedStates?.split(',').includes(region);

  const {
    applepayEnabled,
    bitcoinOpenNodeEnabled: openNodeEnabledOnPage,
    googlepayEnabled,
  } = actionPage.paymentConfiguration || {};

  const openNodeEnabled = openNodeEnabledOnPage && enableOpenNode;

  const clearExpressCheckoutMethod = useCallback(
    () => setValue('expressCheckoutMethod', null),
    [setValue]
  );

  const { selectedItem: selectedCarouselItem, setCarouselItem } = useCarouselItemAndDirection();

  const payWithCardOrBank = useCallback(() => {
    setCarouselItem(selectedCarouselItem + 1);
  }, [selectedCarouselItem, setCarouselItem]);

  return (
    <div
      className="ease flex w-full flex-col items-center gap-4 rounded-2xl border-2 border-neutral-200 px-4 py-4
        transition-all duration-200"
    >
      <div
        className="flex flex-col gap-2"
        style={{
          alignItems: alignCheckoutLabel,
          alignSelf: alignCheckoutLabel,
        }}
      >
        <Label variant="medium">{checkoutLabel || t('donorId.expressCheckout')}</Label>
        {showSignInPrompt ? <SignInLink actionPage={actionPage} /> : null}
      </div>
      {showPayWithCardOrBankButton && !expressCheckoutMethod ? (
        <div
          className={clsx(
            'ease w-full transition-all duration-200',
            (totalAmount === 0 && !eventTicketsAttributes) || isDisallowedState
              ? 'pointer-events-none cursor-not-allowed opacity-[0.5]'
              : 'opacity-1 cursor-pointer'
          )}
        >
          <Button
            className="w-full"
            isDisabled={isPreview}
            leftIcon={
              <div className="flex items-center">
                <VisaColorIcon className="w-[32px]" />
                <MasterCardColorIcon className="w-[32px]" />
                <AmericanExpressColorIcon className="w-[32px]" />
                <DiscoverColorIcon className="w-[32px]" />
              </div>
            }
            onClick={payWithCardOrBank}
            size="lg"
            variant="primary"
          >
            {t('payWithCardOrBank')}
          </Button>
        </div>
      ) : null}
      {expressCheckoutMethod || applepayEnabled || googlepayEnabled || openNodeEnabled ? (
        <div
          className={clsx(
            'ease flex w-full transition-all duration-200',
            expressCheckoutMethod ? 'gap-0' : 'gap-2',
            (totalAmount === 0 && !eventTicketsAttributes) || isLoading || isDisallowedState
              ? 'pointer-events-none opacity-50'
              : 'opacity-1 cursor-pointer'
          )}
        >
          {applepayEnabled && (!expressCheckoutMethod || expressCheckoutMethod === 'applepay') ? (
            <ExpressApplePayButton
              actionPage={actionPage}
              fieldPrefix={fieldPrefix}
              fieldPrefixDelimiter={fieldPrefixDelimiter}
              isCustomDomain={isCustomDomain}
              isDisabled={isPreview || isLoading || isDisallowedState}
              isEmbedded={isEmbedded}
            />
          ) : null}
          {googlepayEnabled && (!expressCheckoutMethod || expressCheckoutMethod === 'googlepay') ? (
            <ExpressGooglePayButton
              actionPage={actionPage}
              fieldPrefix={fieldPrefix}
              fieldPrefixDelimiter={fieldPrefixDelimiter}
              isCustomDomain={isCustomDomain}
              isEmbedded={isEmbedded}
              isPreview={isPreview}
              totalAmount={totalAmount}
            />
          ) : null}
          {openNodeEnabled &&
          (!expressCheckoutMethod || expressCheckoutMethod === 'bitcoin_open_node') ? (
            <ExpressOpenNodeButton
              isDisabled={isPreview || isLoading}
              isLoading={isLoading}
              isPreview={isPreview}
            />
          ) : null}
        </div>
      ) : null}
      {expressCheckoutMethod ? (
        <Button
          className="animate-fade-in cursor-pointer transition-all duration-200 ease-in"
          key="choose-payment-method"
          onClick={clearExpressCheckoutMethod}
          type="button"
          variant="unstyled"
        >
          <Meta className="!text-blue-600" variant="regular">
            {t('donorId.chooseDifferent')}
          </Meta>
        </Button>
      ) : null}
    </div>
  );
};

